/// {@category Misc}
library;

// Package imports:
import 'package:riverpod_annotation/riverpod_annotation.dart';

/// Mimics Either (either_dart) but can have both values
sealed class Result<L, R> {
  const Result();

  /// Whether this [Result] has [left].
  bool get hasLeft => this is Left<L, R>;

  /// Whether this [Result] has [right].
  bool get hasRight => this is Right<L, R>;

  /// If this [Result] has the value [left], return it. If not, throws an error.
  L get left => this is Left<L, R>
      ? (this as Left<L, R>)._leftValue
      : throw Exception('Illegal use. You should check hasLeft before calling');

  /// If this [Result] has the value [right], return it. If not, throws an error.
  R get right => this is Right<L, R>
      ? (this as Right<L, R>)._rightValue
      : throw Exception(
          'Illegal use. You should check hasRight before calling');

  /// Call functions according to [hasLeft] and [hasRight]. If both are true,
  /// both functions are called and return a return value of [right].
  T fold<T>(T Function(L) left, T Function(R) right) {
    dynamic result;
    if (hasLeft) {
      result = left(this.left);
    }
    if (hasRight) {
      result = right(this.right);
    }
    return result as T;
  }
}

/// Result with [left] value only.
class Left<L, R> extends Result<L, R> {
  final L _leftValue;

  const Left(this._leftValue);
}

/// Result with [right] value only.
class Right<L, R> extends Result<L, R> {
  final R _rightValue;

  const Right(this._rightValue);
}

/// Result with both [left] and [right] values.
class Both<L, R> extends Result<L, R> implements Left<L, R>, Right<L, R> {
  @override
  final L _leftValue;
  @override
  final R _rightValue;

  const Both(this._leftValue, this._rightValue);
}

extension AsyncValueWithResultExt<L, R> on AsyncValue<Result<L, R>> {
  T fold<T>({
    required T Function() loading,
    required T Function(L) error,
    required T Function(R) data,
  }) {
    return when(
      loading: loading,
      error: (err, stackTrace) => error(err as L),
      data: (result) {
        dynamic value;
        if (result.hasLeft) {
          value = error(result.left);
        }
        if (result.hasRight) {
          value = data(result.right);
        }
        return value as T;
      },
    );
  }
}

/// {@category Data}
library;

// Dart imports:
import 'dart:ui';

// Flutter imports:
import 'package:flutter/foundation.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/failure/bad_request_failure.dart';
import 'package:baseball_detector_flutter/l10n/l10n.dart';

typedef FailureDescription = String Function(L10n);

/// Represents all app failures
sealed class Failure implements Exception {
  final String type;
  final String code;
  final FailureDescription description;
  final Object? underlyingException;
  late final StackTrace stackTrace;

  Failure({
    required this.type,
    required this.code,
    required this.description,
    this.underlyingException,
    StackTrace? stackTrace,
  }) {
    this.stackTrace = stackTrace ?? StackTrace.current;
  }

  static L10n get _defaultL10n => lookupL10n(const Locale('en'));

  String get message => description(_defaultL10n);

  @override
  String toString() {
    return 'Failure.$type(${formatArgs()})';
  }

  String translate(L10n? l10n) {
    l10n ??= _defaultL10n;
    return '${description(l10n)} [$code]';
  }

  @protected
  String formatArgs() {
    return 'code: $code, description: ${description(_defaultL10n)}';
  }

  /// Creates a BadRequestFailure from response data
  static BadRequestFailure _createBadRequestFailure({
    required String code,
    required int status,
    FailureDescription? description,
    String? title,
    Object? response,
    Object? underlyingException,
    StackTrace? stackTrace,
  }) {
    // Extract message from response if available
    String? message;
    if (response is Map<String, dynamic>) {
      message = response['message'] as String?;
    }

    // Use message-based factory if message is available
    if (message != null) {
      return BadRequestFailure.fromMessage(
        message,
        code: code,
        status: status,
        description: description,
        title: title,
        response: response,
        underlyingException: underlyingException,
        stackTrace: stackTrace,
      );
    }

    // Fallback to generic BadRequestFailure
    return BadRequestFailure(
      code: code,
      status: status,
      description: description,
      title: title,
      response: response,
      underlyingException: underlyingException,
      stackTrace: stackTrace,
    );
  }

  /// Represents http response error
  factory Failure.httpResponse({
    required String code,
    required int status,
    FailureDescription? description,
    String? title,
    Object? response,
    Object? underlyingException,
    StackTrace? stackTrace,
  }) {
    return switch (status) {
      // 4xx Client Error
      400 => _createBadRequestFailure(
          code: code,
          status: status,
          description: description,
          title: title,
          response: response,
          underlyingException: underlyingException,
          stackTrace: stackTrace,
        ),
      401 => UnauthorizedFailure._(
          code: code,
          status: status,
          description: description,
          title: title,
          response: response,
          underlyingException: underlyingException,
          stackTrace: stackTrace,
        ),
      403 => ForbiddenFailure._(
          code: code,
          status: status,
          description: description,
          title: title,
          response: response,
          underlyingException: underlyingException,
          stackTrace: stackTrace,
        ),
      404 => NotFoundFailure._(
          code: code,
          status: status,
          description: description,
          title: title,
